tasks.solution:
#include <iostream>
#include <cmath>

// Function to check if a number is prime
bool isPrime(int n) {
    if (n <= 1) return false;
    for (int i = 2; i <= std::sqrt(n); i++) {
        if (n % i == 0) return false;
    }
    return true;
}

// Function to calculate the square of a number
int calculateSquare(int n) {
    return n * n;
}

int main() {
    int num;
    if (!(std::cin >> num)) return 0;

    if (isPrime(num)) {
        std::cout << num << " is prime." << std::endl;
    } else {
        std::cout << num << " is not prime." << std::endl;
    }

    std::cout << "Square: " << calculateSquare(num) << std::endl;

    return 0;
}
